const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const followUpDiscount = (base: number, contractIndex: number): number =>
  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;

const quoteStep = (
  step: Step,
  customer: { yearsWithMHPCO: number },
  contractIndex: number,
): { premium: number } => {
  const base = computeBasePremium(step.items);
  const itemSurcharges = sumItemSurcharges(step.items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  const discounts = loyaltyDiscount(base, customer) + followUpDiscount(base, contractIndex);
  return {
    premium: Math.ceil(
      base + itemSurcharges + firstInsuranceSurcharge - discounts + PROCESSING_FEE,
    ),
  };
};

export const runScenario = (scenario: unknown): unknown => {
  const { customer, steps } = scenario as Scenario;
  let contractIndex = 0;
  const results = steps.map((step) => {
    const result = quoteStep(step, customer, contractIndex);
    contractIndex += 1;
    return result;
  });
  return { results };
};
